const states = ["Inhala", "Mant\xe9n", "Exhala", "Mant\xe9n"], stateColors = ["rgba(7, 3, 140, 0.4)", "rgba(0, 169, 128, 0.4)", "rgba(31, 105, 215, 0.5)", "rgba(64, 191, 194, 0.4)"]; let stateIndex = 0, intervalTime = 4e3, intervalId, stateStart = !1; const breathingText = document.getElementById("breathing-text"), breathingContainer = document.getElementById("breathing-container"), timeSlider = document.getElementById("time-slider"), timeValue = document.getElementById("time-value"), timeBar = document.getElementById("time-bar"), startButton = document.getElementById("start-button"); function updateBreathing() { breathingText.textContent = states[stateIndex], timeBar.style.backgroundColor = stateColors[stateIndex], stateIndex = (stateIndex + 1) % states.length, resetTimeBar() } function startBreathing() { clearInterval(intervalId), intervalId = setInterval(updateBreathing, intervalTime), resetTimeBar() } function resetTimeBar() { timeBar.style.transition = "none", timeBar.style.width = "0%", setTimeout(() => { timeBar.style.transition = `width ${intervalTime}ms linear`, timeBar.style.width = "100%" }, 50) } timeSlider.addEventListener("input", t => { let e = t.target.value; timeValue.textContent = e, intervalTime = 1e3 * e }), startButton.addEventListener("click", () => { stateStart ? (stateStart = !1, timeSlider.disabled = !1, startButton.textContent = "Iniciar", clearInterval(intervalId), breathingText.textContent = "Va de nuevo", timeBar.style.transition = "none", timeBar.style.width = "100%", setTimeout(() => { timeBar.style.transition = "width 0ms linear", timeBar.style.width = "0%" }, 50)) : (stateStart = !0, timeSlider.disabled = !0, startButton.textContent = "Reiniciar", stateIndex = 0, startBreathing()) });
